    public interface Emitter<T> {

        Emitter<T> next(Consumer<? super T> action);


        default Spliterator<T> spliterator() {
            return new EmitterSpliterator<>(this);
        }


        default StreamEx<T> stream() {
            return of(spliterator());
        }
    }
